1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	const basePremiumFor = (items: { type: string }[]): number =>
12	  items.length === 0 ? 0 : BASE_PREMIUMS[items[0].type];
13	
14	export const runScenario = (scenario: any): unknown => {
15	  const base = basePremiumFor(scenario.steps[0].items);
16	  const premium = base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE;
17	  return { results: [{ premium }] };
18	};
